<?php
namespace Database\Seeders;use App\Models\CharacterClass;use App\Models\Item;use Illuminate\Database\Seeder;use Illuminate\Support\Facades\DB;use RuntimeException;
class EquipmentRequirementsTestingSeeder extends Seeder{public function run(){if(!app()->environment('testing')||substr((string)DB::connection()->getDatabaseName(),-8)!=='_testing')throw new RuntimeException('EquipmentRequirementsTestingSeeder requires an isolated _testing database.');$classes=[];foreach([['adventurer','Aventurero',0],['warrior','Guerrero',10],['paladin','Paladín',20],['mage','Mago',30]] as $row)$classes[$row[0]]=CharacterClass::updateOrCreate(['code'=>$row[0]],['name'=>$row[1],'description'=>'Clase provisional para requisitos de testing.','status'=>'active','sort_order'=>$row[2]]);$items=[['requirements_common_sword','Espada común',1,[]],['requirements_veteran_sword','Espada veterana',5,[]],['requirements_mage_staff','Bastón del mago',1,['mage']],['requirements_sacred_weapon','Arma sagrada',3,['warrior','paladin']]];foreach($items as $row){$item=Item::updateOrCreate(['code'=>$row[0]],['name'=>$row[1],'description'=>'Fixture visual de testing; balance pendiente.','item_type'=>'equipment','equipment_type'=>'weapon','hand_requirement'=>$row[0]==='requirements_mage_staff'?'two_hand':'one_hand','equipment_family'=>$row[0]==='requirements_mage_staff'?'staff':'sword','required_level'=>$row[2],'rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);$item->allowedCharacterClasses()->sync(array_map(function($code)use($classes){return$classes[$code]->id;},$row[3]));}}}
